      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const { projects, ProjectNotFoundError, TaskNotFoundError } = require('../projects/service');

function getTasks(projectId) {
  const project = projects[projectId];
  if (!project) {
    throw new ProjectNotFoundError();
  }
  return project.tasks;
}

function createTask(projectId, title) {
  const project = projects[projectId];
  if (!project) {
    throw new ProjectNotFoundError();
  }
  const taskId = randomUUID();
  const task = { id: taskId, title, status: 'todo' };
  project.tasks.push(task);
  return task;
}

function updateTaskStatus(projectId, taskId, status) {
  const project = projects[projectId];
  if (!project) {
    throw new ProjectNotFoundError();
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    throw new TaskNotFoundError();
  }
  task.status = status;
  return task;
}

module.exports = { getTasks, createTask, updateTaskStatus };
