      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('node:crypto');

let projects = {};

class ProjectNotFoundError extends Error {}
class TaskNotFoundError extends Error {}
class MemberAlreadyExistsError extends Error {}
class BadRequestError extends Error {}

function getProjects() {
  return Object.values(projects);
}

function createProject(name) {
  if (!name) {
    throw new BadRequestError();
  }
  const projectId = randomUUID();
  projects[projectId] = { id: projectId, name, members: [], tasks: [] };
  return projects[projectId];
}

module.exports = { getProjects, createProject, ProjectNotFoundError, TaskNotFoundError, MemberAlreadyExistsError, BadRequestError, projects };
